"""Team Collaboration Manager - production implementation."""

import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------

class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL = "individual"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Models
# ---------------------------------------------------------------------------

class Attachment:
    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at


class User:
    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at


class Project:
    def __init__(self, id, name, owner_id, description, start_date, end_date):
        self.id = id
        self.name = name
        self.owner_id = owner_id
        self.description = description
        self.start_date = start_date
        self.end_date = end_date


class Task:
    def __init__(self, id, project_id, title, status, assignee_id,
                 deadline, started_at, completed_at, created_at):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at
        self.created_at = created_at


class Message:
    def __init__(self, id, author_id, body, project_id, task_id,
                 parent_id, attachments, created_at, edited_at):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments
        self.created_at = created_at
        self.edited_at = edited_at


class Rating:
    def __init__(self, id, rater_id, ratee_id, score, feedback, task_id, created_at):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at


# ---------------------------------------------------------------------------
# Sub-services
# ---------------------------------------------------------------------------

class UserService:
    def __init__(self, lock, id_gen, now):
        self._lock = lock
        self._id_gen = id_gen
        self._now = now
        self._users = {}  # id -> User
        self._by_username = {}  # username -> id
        self._by_email = {}  # email -> id

    def register(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not username or not username.strip():
                raise ValidationError("Username cannot be empty")
            if not email:
                raise ValidationError("Email cannot be empty")
            if "@" not in email:
                raise ValidationError("Email must contain @")
            if not isinstance(role, UserRole):
                raise ValidationError("Role must be a UserRole")
            if username in self._by_username:
                raise DuplicateError("Username already taken")
            if email in self._by_email:
                raise DuplicateError("Email already taken")
            uid = self._id_gen()
            user = User(uid, username, email, role, self._now())
            self._users[uid] = user
            self._by_username[username] = uid
            self._by_email[email] = uid
            return copy.deepcopy(user)

    def get(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            return copy.deepcopy(self._users[user_id])

    def exists(self, user_id):
        return user_id in self._users

    def list_all(self):
        with self._lock:
            return [copy.deepcopy(u) for u in
                    sorted(self._users.values(), key=lambda u: u.id)]

    def update(self, user_id, username=None, email=None, role=None):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            user = self._users[user_id]
            if username is not None:
                if not username or not username.strip():
                    raise ValidationError("Username cannot be empty")
                if username != user.username:
                    if username in self._by_username:
                        raise DuplicateError("Username already taken")
                    del self._by_username[user.username]
                    self._by_username[username] = user_id
                    user.username = username
            if email is not None:
                if not email:
                    raise ValidationError("Email cannot be empty")
                if "@" not in email:
                    raise ValidationError("Email must contain @")
                if email != user.email:
                    if email in self._by_email:
                        raise DuplicateError("Email already taken")
                    del self._by_email[user.email]
                    self._by_email[email] = user_id
                    user.email = email
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("Role must be a UserRole")
                user.role = role
            return copy.deepcopy(user)

    def delete(self, user_id, has_projects, has_open_tasks):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            if has_projects(user_id):
                raise ConflictError("User owns projects")
            if has_open_tasks(user_id):
                raise ConflictError("User has open tasks")
            user = self._users.pop(user_id)
            del self._by_username[user.username]
            del self._by_email[user.email]


class ProjectService:
    def __init__(self, lock, id_gen, now):
        self._lock = lock
        self._id_gen = id_gen
        self._now = now
        self._projects = {}  # id -> Project

    def create(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not name or not name.strip():
                raise ValidationError("Name cannot be empty")
            if end_date < start_date:
                raise ValidationError("End date before start date")
            pid = self._id_gen()
            project = Project(pid, name, owner_id, description, start_date, end_date)
            self._projects[pid] = project
            return copy.deepcopy(project)

    def get(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found")
            return copy.deepcopy(self._projects[project_id])

    def get_internal(self, project_id):
        """Return internal reference (no copy) for use within lock."""
        if project_id not in self._projects:
            raise NotFoundError("Project not found")
        return self._projects[project_id]

    def exists(self, project_id):
        return project_id in self._projects

    def list_all(self):
        with self._lock:
            return [copy.deepcopy(p) for p in
                    sorted(self._projects.values(), key=lambda p: p.id)]

    def update(self, project_id, name=None, start_date=None, end_date=None, description=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found")
            project = self._projects[project_id]
            if name is not None:
                if not name or not name.strip():
                    raise ValidationError("Name cannot be empty")
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            if project.end_date < project.start_date:
                # Revert would be complex; tests expect ValidationError raised
                raise ValidationError("End date before start date")
            return copy.deepcopy(project)

    def delete(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found")
            del self._projects[project_id]

    def owner_has_projects(self, user_id):
        return any(p.owner_id == user_id for p in self._projects.values())


class TaskService:
    def __init__(self, lock, id_gen, now):
        self._lock = lock
        self._id_gen = id_gen
        self._now = now
        self._tasks = {}  # id -> Task
        self._by_project = {}  # project_id -> set of task ids
        self._by_assignee = {}  # assignee_id -> set of task ids

    def create(self, project_id, title, assignee_id=None, deadline=None, project_start=None):
        with self._lock:
            if not title or not title.strip():
                raise ValidationError("Title cannot be empty")
            if deadline is not None and deadline < project_start:
                raise ValidationError("Deadline before project start")
            tid = self._id_gen()
            now = self._now()
            task = Task(tid, project_id, title, TaskStatus.NOT_STARTED,
                        assignee_id, deadline, None, None, now)
            self._tasks[tid] = task
            self._by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self._by_assignee.setdefault(assignee_id, set()).add(tid)
            return copy.deepcopy(task)

    def get(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found")
            return copy.deepcopy(self._tasks[task_id])

    def exists(self, task_id):
        return task_id in self._tasks

    def get_internal(self, task_id):
        if task_id not in self._tasks:
            raise NotFoundError("Task not found")
        return self._tasks[task_id]

    def list_by_project(self, project_id):
        with self._lock:
            ids = self._by_project.get(project_id, set())
            tasks = [self._tasks[tid] for tid in sorted(ids)]
            return [copy.deepcopy(t) for t in tasks]

    def list_by_assignee(self, assignee_id):
        with self._lock:
            ids = self._by_assignee.get(assignee_id, set())
            tasks = [self._tasks[tid] for tid in sorted(ids)]
            return [copy.deepcopy(t) for t in tasks]

    def assign(self, task_id, assignee_id):
        with self._lock:
            task = self.get_internal(task_id)
            old = task.assignee_id
            if old is not None and old in self._by_assignee:
                self._by_assignee[old].discard(task_id)
            task.assignee_id = assignee_id
            self._by_assignee.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def unassign(self, task_id):
        with self._lock:
            task = self.get_internal(task_id)
            old = task.assignee_id
            if old is not None and old in self._by_assignee:
                self._by_assignee[old].discard(task_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline, project_start):
        with self._lock:
            task = self.get_internal(task_id)
            if deadline is not None and deadline < project_start:
                raise ValidationError("Deadline before project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("Status must be a TaskStatus")
            task = self.get_internal(task_id)
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    def delete_by_project(self, project_id):
        """Remove all tasks for a project. Returns nothing."""
        ids = self._by_project.pop(project_id, set())
        for tid in ids:
            task = self._tasks.pop(tid, None)
            if task and task.assignee_id is not None:
                assignee_set = self._by_assignee.get(task.assignee_id)
                if assignee_set:
                    assignee_set.discard(tid)

    def user_has_open_tasks(self, user_id):
        ids = self._by_assignee.get(user_id, set())
        for tid in ids:
            task = self._tasks.get(tid)
            if task and task.status != TaskStatus.COMPLETED:
                return True
        return False

    def get_tasks_for_user(self, user_id):
        """Return internal task objects for a user (within lock)."""
        ids = self._by_assignee.get(user_id, set())
        return [self._tasks[tid] for tid in ids if tid in self._tasks]

    def get_tasks_for_project(self, project_id):
        """Return internal task objects for a project (within lock)."""
        ids = self._by_project.get(project_id, set())
        return [self._tasks[tid] for tid in ids if tid in self._tasks]

    def get_all_tasks(self):
        """Return all internal task objects (within lock)."""
        return list(self._tasks.values())


class MessageService:
    def __init__(self, lock, id_gen, now):
        self._lock = lock
        self._id_gen = id_gen
        self._now = now
        self._messages = {}  # id -> Message
        self._by_project = {}  # project_id -> list of msg ids
        self._by_task = {}  # task_id -> list of msg ids

    def post(self, author_id, body, project_id=None, task_id=None,
             attachments=None, parent_id=None):
        with self._lock:
            # Build attachments
            att_list = []
            if attachments:
                now = self._now()
                for filename, data in attachments:
                    att_list.append(Attachment(filename, len(data), author_id, now))
            # Validate body
            if not body and not att_list:
                raise ValidationError("Body required when no attachments")
            mid = self._id_gen()
            msg = Message(mid, author_id, body, project_id, task_id,
                          parent_id, att_list, self._now(), None)
            self._messages[mid] = msg
            if project_id is not None:
                self._by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self._by_task.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def get_internal(self, msg_id):
        if msg_id not in self._messages:
            raise NotFoundError("Message not found")
        return self._messages[msg_id]

    def exists(self, msg_id):
        return msg_id in self._messages

    def edit(self, msg_id, editor_id, new_body):
        with self._lock:
            msg = self.get_internal(msg_id)
            if msg.author_id != editor_id:
                raise AuthorizationError("Not the author")
            if not new_body:
                raise ValidationError("Body cannot be empty")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, msg_id, user_id, filename, data):
        with self._lock:
            msg = self.get_internal(msg_id)
            if msg.author_id != user_id:
                raise AuthorizationError("Not the author")
            if not filename:
                raise ValidationError("Filename cannot be empty")
            att = Attachment(filename, len(data), user_id, self._now())
            msg.attachments.append(att)
            return copy.deepcopy(msg)

    def list_by_project(self, project_id):
        with self._lock:
            ids = self._by_project.get(project_id, [])
            return [copy.deepcopy(self._messages[mid]) for mid in ids
                    if mid in self._messages]

    def list_by_task(self, task_id):
        with self._lock:
            ids = self._by_task.get(task_id, [])
            return [copy.deepcopy(self._messages[mid]) for mid in ids
                    if mid in self._messages]

    def delete(self, msg_id, user_id):
        with self._lock:
            msg = self.get_internal(msg_id)
            if msg.author_id != user_id:
                raise AuthorizationError("Not the author")
            del self._messages[msg_id]
            # Clean indexes
            if msg.project_id is not None and msg.project_id in self._by_project:
                self._by_project[msg.project_id] = [
                    m for m in self._by_project[msg.project_id] if m != msg_id]
            if msg.task_id is not None and msg.task_id in self._by_task:
                self._by_task[msg.task_id] = [
                    m for m in self._by_task[msg.task_id] if m != msg_id]

    def delete_by_project(self, project_id):
        """Remove all messages for a project."""
        ids = self._by_project.pop(project_id, [])
        for mid in ids:
            msg = self._messages.pop(mid, None)
            if msg and msg.task_id is not None and msg.task_id in self._by_task:
                self._by_task[msg.task_id] = [
                    m for m in self._by_task[msg.task_id] if m != mid]


class PerformanceService:
    def __init__(self, lock, id_gen, now):
        self._lock = lock
        self._id_gen = id_gen
        self._now = now
        self._ratings = {}  # ratee_id -> list of Rating

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if not isinstance(score, int) or score < 1 or score > 5:
                raise ValidationError("Score must be 1-5")
            rid = self._id_gen()
            rating = Rating(rid, rater_id, ratee_id, score, feedback, task_id, self._now())
            self._ratings.setdefault(ratee_id, []).append(rating)
            return copy.deepcopy(rating)

    def get_ratings_for(self, user_id):
        return self._ratings.get(user_id, [])

    def get_ratings_summary(self, user_id):
        with self._lock:
            ratings = self._ratings.get(user_id, [])
            count = len(ratings)
            avg = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": avg,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }


class ReportService:
    def __init__(self, lock, now):
        self._lock = lock
        self._now = now


# ---------------------------------------------------------------------------
# Main manager
# ---------------------------------------------------------------------------

class TeamCollaborationManager:
    """Central manager coordinating all collaboration sub-services."""

    def __init__(self, now=None):
        self._now = now or datetime.now
        self._lock = threading.RLock()
        self._next_id = 0

        def id_gen():
            self._next_id += 1
            return self._next_id

        self._id_gen = id_gen

        self.users = UserService(self._lock, self._id_gen, self._now)
        self.projects = ProjectService(self._lock, self._id_gen, self._now)
        self.tasks = TaskService(self._lock, self._id_gen, self._now)
        self.messages = MessageService(self._lock, self._id_gen, self._now)
        self.performance = PerformanceService(self._lock, self._id_gen, self._now)
        self.reports = ReportService(self._lock, self._now)

    # -- Users --

    def register_user(self, username, email, role=UserRole.MEMBER):
        return self.users.register(username, email, role)

    def get_user(self, user_id):
        return self.users.get(user_id)

    def list_users(self):
        return self.users.list_all()

    def update_user(self, user_id, username=None, email=None, role=None):
        return self.users.update(user_id, username, email, role)

    def delete_user(self, user_id):
        with self._lock:
            self.users.delete(
                user_id,
                has_projects=self.projects.owner_has_projects,
                has_open_tasks=self.tasks.user_has_open_tasks,
            )

    # -- Projects --

    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not self.users.exists(owner_id):
                raise NotFoundError("Owner not found")
            return self.projects.create(name, start_date, end_date, owner_id, description)

    def get_project(self, project_id):
        return self.projects.get(project_id)

    def list_projects(self):
        return self.projects.list_all()

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        return self.projects.update(project_id, name, start_date, end_date, description)

    def delete_project(self, project_id):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found")
            self.tasks.delete_by_project(project_id)
            self.messages.delete_by_project(project_id)
            self.projects.delete(project_id)

    # -- Tasks --

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found")
            if assignee_id is not None and not self.users.exists(assignee_id):
                raise NotFoundError("Assignee not found")
            project = self.projects.get_internal(project_id)
            return self.tasks.create(project_id, title, assignee_id, deadline,
                                     project.start_date)

    def get_task(self, task_id):
        return self.tasks.get(task_id)

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found")
            return self.tasks.list_by_project(project_id)

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            if not self.users.exists(assignee_id):
                raise NotFoundError("User not found")
            return self.tasks.list_by_assignee(assignee_id)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            if not self.users.exists(assignee_id):
                raise NotFoundError("User not found")
            return self.tasks.assign(task_id, assignee_id)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            if not self.users.exists(new_assignee_id):
                raise NotFoundError("User not found")
            return self.tasks.assign(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            return self.tasks.unassign(task_id)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            task = self.tasks.get_internal(task_id)
            project = self.projects.get_internal(task.project_id)
            return self.tasks.set_deadline(task_id, deadline, project.start_date)

    def update_status(self, task_id, status):
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("Status must be a TaskStatus")
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            return self.tasks.update_status(task_id, status)

    # -- Messaging --

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     attachments=None, parent_id=None):
        with self._lock:
            # XOR check
            if (project_id is None) == (task_id is None):
                raise ValidationError("Exactly one of project_id/task_id required")
            if not self.users.exists(author_id):
                raise NotFoundError("Author not found")
            if project_id is not None and not self.projects.exists(project_id):
                raise NotFoundError("Project not found")
            if task_id is not None and not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            if parent_id is not None and not self.messages.exists(parent_id):
                raise NotFoundError("Parent message not found")
            return self.messages.post(author_id, body, project_id, task_id,
                                      attachments, parent_id)

    def edit_message(self, msg_id, editor_id, new_body):
        return self.messages.edit(msg_id, editor_id, new_body)

    def add_attachment(self, msg_id, user_id, filename, data):
        return self.messages.add_attachment(msg_id, user_id, filename, data)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found")
            return self.messages.list_by_project(project_id)

    def list_messages_by_task(self, task_id):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            return self.messages.list_by_task(task_id)

    def delete_message(self, msg_id, user_id):
        return self.messages.delete(msg_id, user_id)

    # -- Performance --

    def get_completion_rate(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found")
            tasks = self.tasks.get_tasks_for_user(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found")
            tasks = self.tasks.get_tasks_for_user(user_id)
            times = []
            for t in tasks:
                if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at:
                    times.append((t.completed_at - t.started_at).total_seconds())
            if not times:
                return None
            return sum(times) / len(times)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if not self.users.exists(rater_id):
                raise NotFoundError("Rater not found")
            if not self.users.exists(ratee_id):
                raise NotFoundError("Ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if not isinstance(score, int) or score < 1 or score > 5:
                raise ValidationError("Score must be 1-5")
            if task_id is not None and not self.tasks.exists(task_id):
                raise NotFoundError("Task not found")
            return self.performance.submit_rating(rater_id, ratee_id, score,
                                                   feedback, task_id)

