    def project_progress_report(self, project_id):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found")
            project = self.projects.get_internal(project_id)
            tasks = self.tasks.get_tasks_for_project(project_id)
            total = len(tasks)
            status_counts = {s.value: 0 for s in TaskStatus}
            for t in tasks:
                status_counts[t.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0
            now = self._now()
            overdue = sum(1 for t in tasks
                          if t.deadline is not None
                          and t.deadline < now
                          and t.status != TaskStatus.COMPLETED)
            per_assignee = {}
            for t in tasks:
                if t.assignee_id is not None:
                    if t.assignee_id not in per_assignee:
                        per_assignee[t.assignee_id] = {
                            "total_tasks": 0,
                            "completed_tasks": 0,
                        }
                    per_assignee[t.assignee_id]["total_tasks"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        per_assignee[t.assignee_id]["completed_tasks"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and not self.projects.exists(project_id):
                raise NotFoundError("Project not found")
            if project_id is not None:
                tasks = self.tasks.get_tasks_for_project(project_id)
            else:
                tasks = self.tasks.get_all_tasks()
            # Group by assignee
            by_user = {}
            for t in tasks:
                if t.assignee_id is not None:
                    by_user.setdefault(t.assignee_id, []).append(t)
            rows = []
            for uid, user_tasks in by_user.items():
                total = len(user_tasks)
                completed = sum(1 for t in user_tasks if t.status == TaskStatus.COMPLETED)
                completion_rate = completed / total if total else 0.0
                times = []
                for t in user_tasks:
                    if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at:
                        times.append((t.completed_at - t.started_at).total_seconds())
                avg_time = sum(times) / len(times) if times else None
                ratings = self.performance.get_ratings_for(uid)
                rating_count = len(ratings)
                rating_avg = sum(r.score for r in ratings) / rating_count if rating_count else 0.0
                rows.append({
