    def export_report(self, report, format):
        with self._lock:
            if not isinstance(format, ReportFormat):
                raise ValidationError("Format must be a ReportFormat")
            if not isinstance(report, dict):
                raise ValidationError("Report must be a dict")
            if format == ReportFormat.CSV:
                return self._export_csv(report)
            else:
                return self._export_pdf(report)

    def _export_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        if "rows" in report:
            # Table-style report
            columns = ["user_id", "total_tasks", "completed_tasks",
                       "completion_rate", "average_completion_time",
                       "rating_count", "rating_average"]
            writer.writerow(columns)
            for row in report["rows"]:
                writer.writerow([row.get(c, "") for c in columns])
        else:
            # Key-value style
            writer.writerow(["metric", "value"])
            self._flatten_to_csv(writer, report, "")
        return output.getvalue()

    def _flatten_to_csv(self, writer, data, prefix):
        for key, value in data.items():
            full_key = "{}.{}".format(prefix, key) if prefix else key
            if isinstance(value, dict):
                self._flatten_to_csv(writer, value, full_key)
            elif isinstance(value, list):
                writer.writerow([full_key, str(value)])
            else:
                writer.writerow([full_key, str(value)])

    def _export_pdf(self, report):
        """Generate a minimal valid PDF."""
        lines = []
        self._report_to_lines(report, "", lines)
        text = "\n".join(lines)

        # Build PDF objects
        objects = []

        def obj(content):
            objects.append(content)
            return len(objects)

        # Object 1: Catalog
        obj("1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj")
        # Object 2: Pages
        obj("2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj")
        # Object 3: Page
        obj("3 0 obj\n<< /Type /Page /Parent 2 0 R "
            "/MediaBox [0 0 612 792] /Contents 4 0 R "
            "/Resources << /Font << /F1 5 0 R >> >> >>\nendobj")

        # Object 4: Content stream
        escaped = self._pdf_escape(text)
        stream_lines = ["BT", "/F1 10 Tf", "36 750 Td", "12 TL"]
        for line in escaped.split("\n"):
            stream_lines.append("({}) '".format(line))
        stream_lines.append("ET")
        stream_content = "\n".join(stream_lines)
        stream_obj = "4 0 obj\n<< /Length {} >>\nstream\n{}\nendstream\nendobj".format(
            len(stream_content), stream_content)
        obj(stream_obj)

        # Object 5: Font
        obj("5 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj")

        # Assemble
        body_parts = []
        offsets = []
        header = "%PDF-1.4\n"
        current_offset = len(header)
        for o in objects:
            offsets.append(current_offset)
            part = o + "\n"
            body_parts.append(part)
            current_offset += len(part)

        xref_offset = current_offset
        xref_lines = ["xref", "0 {}".format(len(objects) + 1),
                      "0000000000 65535 f "]
        for off in offsets:
            xref_lines.append("{:010d} 00000 n ".format(off))
        xref_section = "\n".join(xref_lines) + "\n"

        trailer = "trailer\n<< /Size {} /Root 1 0 R >>\nstartxref\n{}\n%%EOF\n".format(
            len(objects) + 1, xref_offset)

        pdf = header + "".join(body_parts) + xref_section + trailer
        return pdf.encode("ascii")

    def _pdf_escape(self, text):
        """Escape special PDF text chars."""
        text = text.replace("\\", "\\\\")
        text = text.replace("(", "\\(")
        text = text.replace(")", "\\)")
        return text

    def _report_to_lines(self, data, prefix, lines):
        if isinstance(data, dict):
            for key, value in data.items():
                full_key = "{}.{}".format(prefix, key) if prefix else str(key)
                if isinstance(value, (dict, list)):
                    self._report_to_lines(value, full_key, lines)
                else:
                    lines.append("{}: {}".format(full_key, value))
        elif isinstance(data, list):
            for i, item in enumerate(data):
                self._report_to_lines(item, "{}[{}]".format(prefix, i), lines)
        else:
            lines.append("{}: {}".format(prefix, data))
